export type ProductAgreementTemplateId = typeof productAgreementTemplates[number]['id'];

export function findProductAgreementTemplate(input: string | null | undefined): ProductAgreementTemplate | null {
  const normalized = normalizeAgreementSearch(input);
  if (!normalized) return null;

  const direct = productAgreementTemplates.find((template) => template.id === normalized);
  if (direct) return direct;

  return productAgreementTemplates.find((template) => {
    const terms = [template.name, template.sourceFile, ...template.aliases].map(normalizeAgreementSearch);
    return terms.some((term) => term && (normalized.includes(term) || term.includes(normalized)));
  }) ?? null;
}

function normalizeAgreementSearch(input: string | null | undefined): string {
  return String(input ?? '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}
